private async Task<IDictionary<string, IOpenApiSecurityScheme>> GetSecuritySchemesAsync()
    {
        if (!_options.InferSecuritySchemes)
        {
            return new Dictionary<string, IOpenApiSecurityScheme>(_options.SecuritySchemes);
        }

        var authenticationSchemes = (_authenticationSchemeProvider is not null)
            ? await _authenticationSchemeProvider.GetAllSchemesAsync()
            : [];

        if (_options.SecuritySchemesSelector != null)
        {
            return _options.SecuritySchemesSelector(authenticationSchemes);
        }

        // Default implementation, currently only supports JWT Bearer scheme
        return authenticationSchemes
            .Where((scheme) => scheme.Name == "Bearer")
            .ToDictionary(
                (scheme) => scheme.Name,
                (scheme) => new OpenApiSecurityScheme
                {
                    Type = SecuritySchemeType.Http,
                    Scheme = "bearer", // "bearer" refers to the header name here
                    In = ParameterLocation.Header,
                    BearerFormat = "Json Web Token"
                } as IOpenApiSecurityScheme);
    }

public InMemoryTable(
    IEntityType entityType,
    IInMemoryTable? baseTable,
    bool sensitiveLoggingEnabled,
    bool nullabilityCheckEnabled)
{
    BaseTable = baseTable;
    _keyValueFactory = entityType.FindPrimaryKey()!.GetPrincipalKeyValueFactory<TKey>();
    _sensitiveLoggingEnabled = sensitiveLoggingEnabled;
    _nullabilityCheckEnabled = nullabilityCheckEnabled;
    _rows = new Dictionary<TKey, object?[]>(_keyValueFactory.EqualityComparer);
    var properties = entityType.GetFlattenedProperties().AsList();
    _propertyCount = properties.Count;

    foreach (var property in properties)
    {
        var converter = property.GetValueConverter()
            ?? property.FindTypeMapping()?.Converter;

        if (converter != null)
        {
            _valueConverters ??= new List<(int, ValueConverter)>();
            _valueConverters.Add((property.GetIndex(), converter));
        }

        var comparer = property.GetKeyValueComparer();
        if (!comparer.IsDefault())
        {
            _valueComparers ??= new List<(int, ValueComparer)>();
            _valueComparers.Add((property.GetIndex(), comparer));
        }
    }
}

private void InitCascaderNodeState(List<CascaderNode> list, CascaderNode parentNode, int level, bool recursive = false)
        {
            if (list == null) return;

            foreach (var node in list)
            {
                node.Level = level;
                node.ParentNode = parentNode;

                if (node.HasChildren)
                {
                    InitCascaderNodeState(node.Children.ToList(), node, level + 1, true);
                }
                else
                {
                    _searchList.Add(new CascaderNode
                    {
                        Label = node.Label,
                        ParentNode = node.ParentNode,
                        Value = node.Value,
                        Disabled = node.Disabled,
                        Level = node.Level
                    });
                }
            }

            if (!recursive)
            {
                _searchList.ForEach(node =>
                {
                    var pathList = new List<CascaderNode>();
                    SetSelectedNodeWithParent(node, ref pathList);
                    pathList.Reverse();
                    node.Label = string.Join(" / ", pathList.Select(x => x.Label));
                });
            }
        }

internal void SetActiveInt(bool active)
        {
            if (this.Active != active)
            {
                this.Active = active;
                this.OnActiveChange.InvokeAsync(active);

                if (Active)
                {
                    if (Collapse.Animation)
                    {
                        HandleExpand();
                    }
                    else
                    {
                        _isActive = true;
                        _isInactive = false;
                        _isHidden = false;
                        StateHasChanged();
                    }
                }
                else
                {
                    if (Collapse.Animation)
                    {
                        HandleCollapse();
                    }
                    else
                    {
                        _isActive = false;
                        _isInactive = true;
                        _isHidden = true;
                        StateHasChanged();
                    }
                }
            }
        }

private void HandleExpand()
        {
            _isActive = true;
            _isInactive = false;
            _isHidden = false;
            _isCollapseEnterPrepare = true;

            CallAfterRender(async () =>
            {
                await UpdateHeight();

                _isCollapseEnterPrepare = false;
                _isCollapseEnterStart = true;
                _warpperStyle = "height: 0px; opacity: 0;";

                CallAfterRender(async () =>
                {
                    _isCollapseEnterStart = false;
                    _isCollapseEnterActive = true;
                    StateHasChanged();
                    await Task.Delay(100);

                    _warpperStyle = $"height: {_warpperHight}px; opacity: 1;";
                    StateHasChanged();
                    await Task.Delay(450);

                    _isCollapseEnterActive = false;
                    _warpperStyle = "";
                    StateHasChanged();
                });

                StateHasChanged();
            });
        }

private void HandleCollapse()
        {
            _isActive = false;
            _isInactive = true;
            _isCollapseLeavePrepare = true;

            CallAfterRender(async () =>
            {
                _isCollapseLeavePrepare = false;
                _isCollapseLeaveStart = true;
                _warpperStyle = $"height: {_warpperHight}px;";

                CallAfterRender(async () =>
                {
                    await Task.Delay(100);
                    _isCollapseLeaveStart = false;
                    _isCollapseLeaveActive = true;

                    _warpperStyle = "height: 0px; opacity: 0;";//still active
                    StateHasChanged();

                    await Task.Delay(450);
                    _isHidden = true; // still height 0
                    _warpperStyle = "";
                    _isCollapseLeaveActive = false;
                    StateHasChanged();
                });

                StateHasChanged();
                await Task.Yield();
            });

            StateHasChanged();
        }

protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            if (firstRender)
            {
                _afterFirstRender = true;
                DomEventListener.AddShared<JsonElement>("window", "beforeunload", Reloading);
            }

            if (_lastDisabledState != Trigger.Disabled)
            {
                if (Ref.Id != null)
                {
                    if (Trigger.Disabled)
                    {
                        await JsInvokeAsync(JSInteropConstants.AddClsToFirstChild, Ref, $"disabled");
                    }
                    else
                    {
                        await JsInvokeAsync(JSInteropConstants.RemoveClsFromFirstChild, Ref, $"disabled");
                    }
                }
                _lastDisabledState = Trigger.Disabled;
            }

            if (_isWaitForOverlayFirstRender && _isOverlayFirstRender)
            {
                _isOverlayFirstRender = false;
                //await Show(_overlayLeft, _overlayTop);

                _isWaitForOverlayFirstRender = false;
                _overlayLeft = null;
                _overlayTop = null;
            }
            await base.OnAfterRenderAsync(firstRender);
        }

internal async Task Show(int? overlayLeft = null, int? overlayTop = null)
        {
            if (_isOverlayShow || Trigger.Disabled)
            {
                return;
            }
            _isOverlayDuringShowing = true;

            if (_isOverlayFirstRender)
            {
                Trigger.SetShouldRender(false);
                await Task.Yield();
            }

            _overlayLeft = overlayLeft;
            _overlayTop = overlayTop;

            if (_isOverlayFirstRender)
            {
                _isWaitForOverlayFirstRender = true;

                await InvokeAsync(StateHasChanged);
            }

            await UpdateParentOverlayState(true);

            await AddOverlayToBody(overlayLeft, overlayTop);
            _isOverlayShow = true;
            _isOverlayDuringShowing = false;
            _isOverlayHiding = false;

            _overlayCls = Trigger.GetOverlayEnterClass();
            await Trigger.OnVisibleChange.InvokeAsync(true);

            if (Trigger != null && Trigger.VisibleChanged.HasDelegate)
            {
                await Trigger.VisibleChanged.InvokeAsync(true);
            }

            await InvokeAsync(StateHasChanged);

            if (OnShow.HasDelegate)
                _ = OnShow.InvokeAsync(null);
        }

protected override void OnInitialized()
        {
            base.OnInitialized();

            Model ??= (TModel)Expression.New(typeof(TModel)).Constructor.Invoke(new object[] { });

            _editContext = new EditContext(Model);

            FormProvider?.AddForm(this);

            if (OnFieldChanged.HasDelegate)
                _editContext.OnFieldChanged += OnFieldChangedHandler;
            if (OnValidationRequested.HasDelegate)
                _editContext.OnValidationRequested += OnValidationRequestedHandler;
            if (OnValidationStateChanged.HasDelegate)
                _editContext.OnValidationStateChanged += OnValidationStateChangedHandler;

            if (UseRulesValidator)
            {
                _editContext.OnFieldChanged += RulesModeOnFieldChanged;
                _editContext.OnValidationRequested += RulesModeOnValidationRequested;
            }

            // If configured, perform validation centrally on any field change (ValidateOnChange)
            if (ValidateOnChange)
            {
                _editContext.OnFieldChanged += ValidateOnChangeOnFieldChanged;
            }

            _previousValidateOnChange = ValidateOnChange;
        }

private void BuildEditContext()
        {
            if (_editContext == null)
                return;

            _isModelBuildFromNull = false;

            if (Model == null)
            {
                _model = (TModel)Expression.New(typeof(TModel)).Constructor.Invoke([]);
                _isModelBuildFromNull = true;
            }

            var newContext = new EditContext(Model);
            foreach (var kv in GetEventInfos())
            {
                FieldInfo fieldInfo = kv.Value.fi;
                EventInfo eventInfo = kv.Value.ei;
                if (fieldInfo.GetValue(_editContext) is Delegate mdel)
                {
                    foreach (Delegate del in mdel.GetInvocationList())
                    {
                        eventInfo.RemoveEventHandler(_editContext, del);
                        eventInfo.AddEventHandler(newContext, del);
                    }
                }
            }
            _editContext = newContext;

            // because EditForm's editcontext CascadingValue is fixed,so there need invoke StateHasChanged,
            // otherwise, the child component's(FormItem) EditContext will not update.
            InvokeAsync(StateHasChanged);
        }

protected override async Task OnInputAsync(ChangeEventArgs args)
        {
            _isInputing = true;
            _inputString = args.Value.ToString();
            await base.OnInputAsync(args);

            if (_duringPressEnterArgs != null)
            {
                if (_duringPressEnterArgs.ShouldPreventLineBreak)
                {
                    if (_inputString?.EndsWith('\n') == true)
                    {
                        // Only remove the last line break
                        if (_inputString.EndsWith("\r\n"))
                        {
                            _inputString = _inputString[..^2];
                        }
                        else
                        {
                            _inputString = _inputString[..^1];
                        }
                        ForceUpdateValueString(_inputString);
                    }
                }

                _duringPressEnterArgs = null;
            }

            if (OnInput.HasDelegate)
            {
                await OnInput.InvokeAsync(args);
            }
        }

private void OptimizeSize(decimal windowWidth)
        {
            var originalCollapsed = _isCollapsed;
            var originlBrokenPoint = _brokenPoint;

            if (windowWidth < (int)Breakpoint)
            {
                _brokenPoint = true;
                _isCollapsed = true;
                _showTrigger = true;
            }
            else
            {
                _brokenPoint = false;
                _isCollapsed = false;
                _showTrigger = false;
            }

            if (originlBrokenPoint != _brokenPoint && OnBreakpoint.HasDelegate)
            {
                OnBreakpoint.InvokeAsync(_brokenPoint);
            }

            if (originalCollapsed != _isCollapsed)
            {
                _menu?.CollapseUpdated(_isCollapsed);

                if (OnCollapse.HasDelegate)
                {
                    OnCollapse.InvokeAsync(_isCollapsed);
                }

                if (CollapsedChanged.HasDelegate)
                {
                    CollapsedChanged.InvokeAsync(_isCollapsed);
                }
            }

            InvokeAsync(StateHasChanged);
        }

public void SetCookieTokenAndHeader(HttpContext httpContext)
    {
        ArgumentNullException.ThrowIfNull(httpContext);

        CheckSSLConfig(httpContext);

        var antiforgeryFeature = GetCookieTokens(httpContext);
        if (!antiforgeryFeature.HaveStoredNewCookieToken && antiforgeryFeature.NewCookieToken != null)
        {
            if (antiforgeryFeature.NewCookieTokenString == null)
            {
                antiforgeryFeature.NewCookieTokenString =
                    _tokenSerializer.Serialize(antiforgeryFeature.NewCookieToken);
            }

            SaveCookieTokenAndHeader(httpContext, antiforgeryFeature.NewCookieTokenString);
            antiforgeryFeature.HaveStoredNewCookieToken = true;
            _logger.NewCookieToken();
        }
        else
        {
            _logger.ReusedCookieToken();
        }

        if (!httpContext.Response.HasStarted)
        {
            SetDoNotCacheHeaders(httpContext);
        }
    }

