public virtual void Dispose()
    {
        if (_disposed)
        {
            return;
        }

        var interceptionResult = default(InterceptionResult);
        try
        {
            Close();

            if (_logger?.ShouldLogDataReaderDispose(DateTimeOffset.UtcNow) == true)
            {
                interceptionResult = _logger.DataReaderDisposing(
                    _relationalConnection,
                    _command,
                    _reader,
                    _commandId,
                    _reader.RecordsAffected,
                    _readCount,
                    _startTime,
                    _stopwatch.Elapsed); // can throw
            }
        }
        finally
        {
            _disposed = true;

            try
            {
                if (!interceptionResult.IsSuppressed)
                {
                    _reader.Dispose();
                    _command.Parameters.Clear();
                    _command.Dispose();
                    _relationalConnection.Close();
                }
            }
            finally
            {
                _reader = null!;
                _command = null!;
                _relationalConnection = null!;
                _logger = null;
            }
        }
    }

protected override bool TryParseValueFromString(string value, out TValue result, out string validationErrorMessage)
        {
            result = default;
            validationErrorMessage = $"{FieldIdentifier.FieldName} field isn't valid.";

            if (string.IsNullOrEmpty(value))
            {
                return false;
            }

            string[] values = value.Split(',');

            if (values.Length != 2)
            {
                return false;
            }

            var success0 = BindConverter.TryConvertTo<DateTime>(values[0], CultureInfo, out var dateTime0);
            var success1 = BindConverter.TryConvertTo<DateTime>(values[1], CultureInfo, out var dateTime1);

            if (success0 && success1)
            {
                result = CreateInstance();

                var array = result as Array;

                array.SetValue(dateTime0, 0);
                array.SetValue(dateTime1, 1);

                validationErrorMessage = null;

                return true;
            }

            return false;
        }

private void PrepareMatrix()
        {
            List<List<(IDescriptionsItem item, int realSpan)>> itemMatrix = [];

            List<(IDescriptionsItem item, int realSpan)> currentRow = [];
            var width = 0;

            var items = Items;
            for (var i = 0; i < items.Count; i++)
            {
                var item = items[i];
                width += item.Span;

                if (width >= _realColumn)
                {
                    currentRow.Add((item, _realColumn - (width - item.Span)));
                    FlushRow();
                }
                else if (i == items.Count - 1)
                {
                    currentRow.Add((item, _realColumn - (width - item.Span)));
                    FlushRow();
                }
                else
                {
                    currentRow.Add((item, item.Span));
                }
            }
            this._itemMatrix = itemMatrix;

            void FlushRow()
            {
                itemMatrix.Add(currentRow);
                currentRow = [];
                width = 0;
            }
        }

private async Task LoadItems(string searchValue)
        {
            if (OnSearch.HasDelegate)
            {
                await OnSearch.InvokeAsync((searchValue, _currentPrefix));
            }

            if (LoadOptions is null)
            {
                var optionsToShow = OriginalOptions.Where(x => x.Value.Contains(searchValue, StringComparison.OrdinalIgnoreCase)).ToList();
                SetOptionsToShow(optionsToShow);
            }
            else
            {
                _cancellationTokenSource?.Cancel();
                _cancellationTokenSource = new CancellationTokenSource();

                try
                {
                    var options = await LoadOptions.Invoke(searchValue, _cancellationTokenSource.Token).ConfigureAwait(false);
                    SetOptionsToShow(options);
                }
                catch (OperationCanceledException)
                {
                    // Operation was cancelled, ignore
                }
            }
        }

private byte[]? GetAndRefresh(string key, bool getData)
    {
        ArgumentNullThrowHelper.ThrowIfNull(key);

        var cache = Connect();

        // This also resets the LRU status as desired.
        // TODO: Can this be done in one operation on the server side? Probably, the trick would just be the DateTimeOffset math.
        RedisValue[] results;
        try
        {
            results = cache.HashGet(_instancePrefix.Append(key), GetHashFields(getData));
        }
        catch (Exception ex)
        {
            OnRedisError(ex, cache);
            throw;
        }

        if (results.Length >= 2)
        {
            MapMetadata(results, out DateTimeOffset? absExpr, out TimeSpan? sldExpr);
            if (sldExpr.HasValue)
            {
                Refresh(cache, key, absExpr, sldExpr.GetValueOrDefault());
            }
        }

        if (results.Length >= 3 && !results[2].IsNull)
        {
            return results[2];
        }

        return null;
    }

private async Task<byte[]?> GetAndRefreshAsync(string key, bool getData, CancellationToken token = default)
    {
        ArgumentNullThrowHelper.ThrowIfNull(key);

        token.ThrowIfCancellationRequested();

        var cache = await ConnectAsync(token).ConfigureAwait(false);
        Debug.Assert(cache is not null);

        // This also resets the LRU status as desired.
        // TODO: Can this be done in one operation on the server side? Probably, the trick would just be the DateTimeOffset math.
        RedisValue[] results;
        try
        {
            results = await cache.HashGetAsync(_instancePrefix.Append(key), GetHashFields(getData)).ConfigureAwait(false);
        }
        catch (Exception ex)
        {
            OnRedisError(ex, cache);
            throw;
        }

        if (results.Length >= 2)
        {
            MapMetadata(results, out DateTimeOffset? absExpr, out TimeSpan? sldExpr);
            if (sldExpr.HasValue)
            {
                await RefreshAsync(cache, key, absExpr, sldExpr.GetValueOrDefault(), token).ConfigureAwait(false);
            }
        }

        if (results.Length >= 3 && !results[2].IsNull)
        {
            return results[2];
        }

        return null;
    }

public ValidationStrategy<T> ThrowOnFailures() {
	_throw = true;
	return this;
}

private IValidatorSelector GetSelector() {
	IValidatorSelector selector = null;

	if (_properties != null || _ruleSets != null || _customSelector != null) {
		var selectors = new List<IValidatorSelector>(3);

		if (_customSelector != null) {
			selectors.Add(_customSelector);
		}

		if (_properties != null) {
			selectors.Add(ValidatorOptions.Global.ValidatorSelectors.MemberNameValidatorSelectorFactory(_properties.ToArray()));
		}

		if (_ruleSets != null) {
			selectors.Add(ValidatorOptions.Global.ValidatorSelectors.RulesetValidatorSelectorFactory(_ruleSets.ToArray()));
		}

		selector = selectors.Count == 1 ? selectors[0] : ValidatorOptions.Global.ValidatorSelectors.CompositeValidatorSelectorFactory(selectors);
	}
	else {
		selector = ValidatorOptions.Global.ValidatorSelectors.DefaultValidatorSelectorFactory();
	}

	return selector;
}

internal ValidationContext<T> BuildContext(T instance) {
	return new ValidationContext<T>(instance, null, GetSelector()) {
		ThrowOnFailures = _throw
	};
}

