                OkText = okText,
                CancelText = cancelText,
                OkType = ButtonType.Primary,
                OnOk = async (e) => await RecoverDraft(),
                OnCancel = async (e) => await DeleteDraft()
            };

            if (RecoveryContentTemplate != null)
            {
