                content = content.Replace("${time}", savedTime);
                confirmOptions.Content = content;
            }

            ModalService.Confirm(confirmOptions);
            return Task.CompletedTask;
        }

private static bool TryExtractCompactAppHostId(string fileName, out string appHostId)
    {
        appHostId = string.Empty;

        if (fileName.Length == CompactAppHostIdLength && IsBase64UrlIdentifier(fileName))
        {
            appHostId = fileName;
            return true;
        }

        var pidSeparatorIndex = CompactAppHostIdLength + CompactInstanceIdLength;
        if (fileName.Length <= pidSeparatorIndex ||
            fileName[pidSeparatorIndex] != '.')
        {
            return false;
        }

        var candidateAppHostId = fileName[..CompactAppHostIdLength];
        var instanceId = fileName[CompactAppHostIdLength..pidSeparatorIndex];
        var pidText = fileName[(pidSeparatorIndex + 1)..];

        if (IsBase64UrlIdentifier(candidateAppHostId) &&
            IsBase64UrlIdentifier(instanceId) &&
            int.TryParse(pidText, NumberStyles.None, CultureInfo.InvariantCulture, out _))
        {
            appHostId = candidateAppHostId;
            return true;
        }

        return false;
    }

public void Save()
    {
        var directory = Path.GetDirectoryName(_secretsFilePath);
        if (!string.IsNullOrEmpty(directory) && !Directory.Exists(directory))
        {
            Directory.CreateDirectory(directory);
        }

        var obj = new JsonObject();
        foreach (var (key, value) in _secrets)
        {
            obj[key] = value;
        }

        var json = obj.ToJsonString(s_jsonOptions);

        // Unix: write to temp file then move for atomicity (matches aspnetcore pattern)
        if (!OperatingSystem.IsWindows())
        {
            var tempFilename = Path.GetTempFileName();
            try
            {
                File.WriteAllText(tempFilename, json);
                File.Move(tempFilename, _secretsFilePath, overwrite: true);
            }
            finally
            {
                // Clean up temp file if move failed
                if (File.Exists(tempFilename))
                {
                    File.Delete(tempFilename);
                }
            }
        }
        else
        {
            File.WriteAllText(_secretsFilePath, json);
        }
    }

private static void LoadAssemblies()
        {
            var assemblyPath = Path.GetDirectoryName(Assembly.GetEntryAssembly()?.Location);
            if (assemblyPath == null) return;

            AssemblyLoadContext.Default.Resolving += ResolveDependencies;

            var assembliesFolder = new DirectoryInfo(assemblyPath);
            var assemblies = AppDomain.CurrentDomain.GetAssemblies();

            // iterate through Oqtane assemblies in /bin ( filter is narrow to optimize loading process )
            foreach (var dll in assembliesFolder.EnumerateFiles($"*.dll", SearchOption.TopDirectoryOnly).Where(f => f.IsOqtaneAssembly()))
            {
                AssemblyName assemblyName;
                try
                {
                    assemblyName = AssemblyName.GetAssemblyName(dll.FullName);
                }
                catch
                {
                    Debug.WriteLine($"Oqtane Error: Cannot Get Assembly Name For {dll.Name}");
                    continue;
                }

                if (!assemblies.Any(a => AssemblyName.ReferenceMatchesDefinition(assemblyName, a.GetName())))
                {
                    AssemblyLoadContext.Default.LoadOqtaneAssembly(dll, assemblyName);
                }
            }
        }

private static string GetTwoToneIconSvg(string iconSvg, string primaryColor, string secondaryColor)
        {
            if (string.IsNullOrWhiteSpace(secondaryColor))
            {
                return iconSvg.Replace("fill=\"#333\"", $"fill=\"{primaryColor}\"");
            }

            iconSvg = iconSvg.Replace("fill=\"#333\"", "fill=\"primaryColor\"")
           .Replace("fill=\"#E6E6E6\"", "fill=\"secondaryColor\"")
           .Replace("fill=\"#D9D9D9\"", "fill=\"secondaryColor\"")
           .Replace("fill=\"#D8D8D8\"", "fill=\"secondaryColor\"");

            var document = XDocument.Load(new StringReader(iconSvg));
            var svgRoot = document.Root;
            foreach (var path in svgRoot.Nodes().OfType<XElement>())
            {
                if (path.Attribute("fill")?.Value == "secondaryColor")
                {
                    path.SetAttributeValue("fill", secondaryColor);
                }
                else
                {
                    path.SetAttributeValue("fill", primaryColor);
                }
            }

            return svgRoot.ToString();
        }

public static string ToIdentifierCompatibleSubstring(this ITypeSymbol type)
        {
            if (type is IArrayTypeSymbol arrayType)
            {
                int rank = arrayType.Rank;
                string suffix = rank == 1 ? "Array" : $"Array{rank}D"; // Array, Array2D, Array3D, ...
                return ToIdentifierCompatibleSubstring(arrayType.ElementType) + suffix;
            }

            string displayString = type.ContainingType is null
                ? type.Name
                : type.ToDisplayString(s_identifierCompatibleFormat).Replace(".", string.Empty);

            if (type is not INamedTypeSymbol { IsGenericType: true } namedType)
            {
                return displayString;
            }

            StringBuilder sb = new(displayString);

            if (namedType.GetAllTypeArgumentsInScope() is List<ITypeSymbol> typeArgsInScope)
            {
                foreach (ITypeSymbol genericArg in typeArgsInScope)
                {
                    sb.Append(ToIdentifierCompatibleSubstring(genericArg));
                }
            }

            return sb.ToString();
        }

